import numpy as np

def rho(h_km):
    """Approximate atmospheric density (kg/m^3)."""
    if h_km < 200: return 3e-10
    if h_km < 300: return 2.4e-11 * np.exp(-(h_km-300)/45)
    if h_km < 400: return 2.4e-11 * np.exp(-(h_km-300)/45)
    if h_km < 500: return 3.7e-12 * np.exp(-(h_km-400)/54)
    if h_km < 600: return 7.0e-13 * np.exp(-(h_km-500)/63)
    if h_km < 700: return 1.5e-13 * np.exp(-(h_km-600)/72)
    return 3.6e-14 * np.exp(-(h_km-700)/89)

sats = [
    ('Sputnik 1', 215, 0.25, 83.6),
    ('Explorer 1', 358, 12.0, 13.97),
    ('Vanguard 1', 654, 300, 1.47),
]

print('Satellite            Perigee  Density(kg/m3)  Life(yr)')
for name, peri, life, mass in sats:
    d = rho(peri)
    print(f'{name:20s} {peri:5d} km  {d:.2e}      {life:6.1f}')

print()
print(f'Density at 358 km: {rho(358):.2e}')
print(f'Density at 654 km: {rho(654):.2e}')
print(f'Ratio: {rho(358)/rho(654):.0f}x')
print(f'A 300 km difference in perigee = {rho(358)/rho(654):.0f}x less drag')
print(f'= ~25x longer orbital lifetime (accounting for other factors)')
